"use client";

import { useState } from "react";
import { motion } from "framer-motion";
import type { ResearchReport } from "@/lib/types";
import { ConfidenceMeter } from "@/components/ConfidenceMeter";
import { SourceCards } from "@/components/SourceCards";
import { ImageGallery } from "@/components/ImageGallery";
import { ExportMenu } from "@/components/ExportMenu";
import {
  BookOpen, TrendingUp, AlertTriangle, Clock,
  Globe, Plus, ChevronDown, ChevronUp,
} from "lucide-react";

interface ReportPanelProps {
  report: ResearchReport;
  onNewResearch: () => void;
}

export function ReportPanel({ report, onNewResearch }: ReportPanelProps) {
  const [showConflicts, setShowConflicts] = useState(false);

  const durationSec = (report.metadata.researchDurationMs / 1000).toFixed(1);

  return (
    <div className="max-w-6xl mx-auto px-6 py-10 space-y-6">
      {/* Header */}
      <motion.div
        initial={{ opacity: 0, y: -10 }}
        animate={{ opacity: 1, y: 0 }}
        className="flex flex-col md:flex-row md:items-center justify-between gap-4"
      >
        <div>
          <div className="flex items-center gap-2 text-xs text-slate-500 mb-2">
            <Clock className="w-3.5 h-3.5" />
            <span>Completed in {durationSec}s</span>
            <span>·</span>
            <Globe className="w-3.5 h-3.5" />
            <span>{report.metadata.totalSourcesAnalyzed} sources analyzed</span>
          </div>
          <h1 className="text-2xl md:text-3xl font-bold text-white leading-tight">
            {report.query}
          </h1>
        </div>
        <div className="flex items-center gap-3 flex-shrink-0">
          <ExportMenu report={report} />
          <button
            onClick={onNewResearch}
            className="btn-gradient px-4 py-2.5 rounded-xl text-sm font-semibold flex items-center gap-2"
          >
            <Plus className="w-4 h-4" />
            New Research
          </button>
        </div>
      </motion.div>

      {/* Top grid: Answer + Confidence */}
      <div className="grid md:grid-cols-3 gap-5">
        {/* Main Answer */}
        <motion.div
          initial={{ opacity: 0, y: 16 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ delay: 0.1 }}
          className="md:col-span-2 glass rounded-2xl p-7"
        >
          <div className="flex items-center gap-2 mb-4">
            <BookOpen className="w-5 h-5 text-purple-400" />
            <h2 className="text-sm font-semibold text-slate-400 uppercase tracking-wider">Answer</h2>
          </div>
          <p className="text-white text-base leading-7 font-medium">{report.answer}</p>
        </motion.div>

        {/* Confidence */}
        <motion.div
          initial={{ opacity: 0, y: 16 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ delay: 0.15 }}
          className="glass rounded-2xl p-7 flex flex-col items-center justify-center"
        >
          <ConfidenceMeter score={report.confidence} />
        </motion.div>
      </div>

      {/* Executive Summary */}
      {report.executiveSummary && (
        <motion.div
          initial={{ opacity: 0, y: 16 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ delay: 0.2 }}
          className="glass rounded-2xl p-7"
        >
          <h2 className="text-sm font-semibold text-slate-400 uppercase tracking-wider mb-4">
            Executive Summary
          </h2>
          <p className="text-slate-300 leading-7">{report.executiveSummary}</p>
        </motion.div>
      )}

      {/* Key Findings + Supporting Data */}
      <div className="grid md:grid-cols-2 gap-5">
        {report.keyFindings?.length > 0 && (
          <motion.div
            initial={{ opacity: 0, y: 16 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.25 }}
            className="glass rounded-2xl p-7"
          >
            <div className="flex items-center gap-2 mb-5">
              <TrendingUp className="w-5 h-5 text-cyan-400" />
              <h2 className="text-sm font-semibold text-slate-400 uppercase tracking-wider">Key Findings</h2>
            </div>
            <ul className="space-y-3">
              {report.keyFindings.map((finding, i) => (
                <li key={i} className="flex items-start gap-3">
                  <span className="w-5 h-5 rounded-full bg-purple-500/20 text-purple-400 text-xs flex items-center justify-center flex-shrink-0 mt-0.5 font-bold">
                    {i + 1}
                  </span>
                  <span className="text-slate-300 text-sm leading-relaxed">{finding}</span>
                </li>
              ))}
            </ul>
          </motion.div>
        )}

        {report.supportingData?.length > 0 && (
          <motion.div
            initial={{ opacity: 0, y: 16 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.3 }}
            className="glass rounded-2xl p-7"
          >
            <h2 className="text-sm font-semibold text-slate-400 uppercase tracking-wider mb-5">
              Supporting Data
            </h2>
            <ul className="space-y-3">
              {report.supportingData.map((d, i) => (
                <li key={i} className="flex items-start gap-3">
                  <div className="w-1.5 h-1.5 rounded-full bg-cyan-400 mt-2 flex-shrink-0" />
                  <span className="text-slate-300 text-sm leading-relaxed">{d}</span>
                </li>
              ))}
            </ul>
          </motion.div>
        )}
      </div>

      {/* Search Intents used */}
      <motion.div
        initial={{ opacity: 0, y: 16 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ delay: 0.35 }}
        className="glass rounded-2xl p-6"
      >
        <h2 className="text-sm font-semibold text-slate-400 uppercase tracking-wider mb-4">
          Research Strategy ({report.metadata.searchIntents.length} Search Intents)
        </h2>
        <div className="flex flex-wrap gap-2">
          {report.metadata.searchIntents.map((intent, i) => (
            <span
              key={i}
              className="px-3 py-1.5 rounded-full text-xs text-slate-300 glass border border-purple-500/20"
            >
              {intent}
            </span>
          ))}
        </div>
      </motion.div>

      {/* Conflicting Evidence */}
      {report.conflictingEvidence?.length > 0 && (
        <motion.div
          initial={{ opacity: 0, y: 16 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ delay: 0.4 }}
          className="glass rounded-2xl p-6 border border-orange-500/20"
        >
          <button
            onClick={() => setShowConflicts(!showConflicts)}
            className="w-full flex items-center justify-between"
          >
            <div className="flex items-center gap-2">
              <AlertTriangle className="w-5 h-5 text-orange-400" />
              <h2 className="text-sm font-semibold text-orange-300">
                Conflicting Evidence Detected ({report.conflictingEvidence.length})
              </h2>
            </div>
            {showConflicts ? (
              <ChevronUp className="w-4 h-4 text-slate-500" />
            ) : (
              <ChevronDown className="w-4 h-4 text-slate-500" />
            )}
          </button>

          {showConflicts && (
            <div className="mt-4 space-y-4">
              {report.conflictingEvidence.map((conflict, i) => (
                <div key={i} className="rounded-xl bg-orange-500/5 p-4 border border-orange-500/10">
                  <p className="text-sm text-slate-300 mb-3 font-medium">{conflict.claim}</p>
                  <div className="grid md:grid-cols-2 gap-3">
                    <div className="rounded-lg bg-white/5 p-3">
                      <p className="text-xs text-slate-500 mb-1">Source A</p>
                      <p className="text-sm text-white font-bold">{conflict.sourceA.value}</p>
                      <a href={conflict.sourceA.url} target="_blank" rel="noopener noreferrer"
                        className="text-xs text-purple-400 hover:text-purple-300 truncate block mt-1">
                        {conflict.sourceA.url}
                      </a>
                    </div>
                    <div className="rounded-lg bg-white/5 p-3">
                      <p className="text-xs text-slate-500 mb-1">Source B</p>
                      <p className="text-sm text-white font-bold">{conflict.sourceB.value}</p>
                      <a href={conflict.sourceB.url} target="_blank" rel="noopener noreferrer"
                        className="text-xs text-purple-400 hover:text-purple-300 truncate block mt-1">
                        {conflict.sourceB.url}
                      </a>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          )}
        </motion.div>
      )}

      {/* Sources */}
      <motion.div
        initial={{ opacity: 0, y: 16 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ delay: 0.45 }}
      >
        <SourceCards sources={report.sources} />
      </motion.div>

      {/* Image Gallery */}
      {report.images?.length > 0 && (
        <motion.div
          initial={{ opacity: 0, y: 16 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ delay: 0.5 }}
        >
          <ImageGallery images={report.images} />
        </motion.div>
      )}
    </div>
  );
}
