"use client";

import { useState } from "react";
import { motion, AnimatePresence } from "framer-motion";
import type { ResearchReport } from "@/lib/types";
import { Download, FileText, Code2, FileJson, ChevronDown } from "lucide-react";

interface ExportMenuProps {
  report: ResearchReport;
}

export function ExportMenu({ report }: ExportMenuProps) {
  const [open, setOpen] = useState(false);

  const exportMarkdown = () => {
    const md = [
      `# Research Report: ${report.query}`,
      `\n**Generated:** ${new Date(report.metadata.timestamp).toLocaleString()}`,
      `**Confidence:** ${report.confidence}%`,
      `**Sources Analyzed:** ${report.metadata.totalSourcesAnalyzed}`,
      `\n## Answer\n\n${report.answer}`,
      `\n## Executive Summary\n\n${report.executiveSummary}`,
      `\n## Key Findings\n\n${report.keyFindings.map((f, i) => `${i + 1}. ${f}`).join("\n")}`,
      `\n## Supporting Data\n\n${report.supportingData.map((d) => `- ${d}`).join("\n")}`,
      `\n## Sources\n\n${report.sources.map((s) => `- [${s.title}](${s.url}) — Authority: ${Math.round(s.authorityScore * 100)}%`).join("\n")}`,
      `\n## Research Strategy\n\n${report.metadata.searchIntents.map((i) => `- ${i}`).join("\n")}`,
    ].join("\n");

    download(md, `research-${Date.now()}.md`, "text/markdown");
    setOpen(false);
  };

  const exportJSON = () => {
    const json = JSON.stringify(report, null, 2);
    download(json, `research-${Date.now()}.json`, "application/json");
    setOpen(false);
  };

  const exportText = () => {
    const txt = [
      `RESEARCH REPORT`,
      `Query: ${report.query}`,
      `Date: ${new Date(report.metadata.timestamp).toLocaleString()}`,
      `Confidence: ${report.confidence}%`,
      ``,
      `ANSWER`,
      report.answer,
      ``,
      `EXECUTIVE SUMMARY`,
      report.executiveSummary,
      ``,
      `KEY FINDINGS`,
      ...report.keyFindings.map((f, i) => `${i + 1}. ${f}`),
      ``,
      `SUPPORTING DATA`,
      ...report.supportingData.map((d) => `• ${d}`),
      ``,
      `SOURCES (${report.sources.length})`,
      ...report.sources.map((s) => `• ${s.title} — ${s.url}`),
    ].join("\n");

    download(txt, `research-${Date.now()}.txt`, "text/plain");
    setOpen(false);
  };

  const download = (content: string, filename: string, type: string) => {
    const blob = new Blob([content], { type });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = filename;
    a.click();
    URL.revokeObjectURL(url);
  };

  return (
    <div className="relative">
      <button
        onClick={() => setOpen(!open)}
        className="flex items-center gap-2 px-4 py-2.5 rounded-xl glass text-sm font-semibold text-slate-300 hover:text-white hover:border-purple-500/40 transition-all"
      >
        <Download className="w-4 h-4" />
        Export
        <ChevronDown className={`w-3.5 h-3.5 transition-transform ${open ? "rotate-180" : ""}`} />
      </button>

      <AnimatePresence>
        {open && (
          <motion.div
            initial={{ opacity: 0, scale: 0.95, y: -8 }}
            animate={{ opacity: 1, scale: 1, y: 0 }}
            exit={{ opacity: 0, scale: 0.95, y: -8 }}
            transition={{ duration: 0.15 }}
            className="absolute right-0 top-full mt-2 w-48 glass-strong rounded-xl overflow-hidden z-20 shadow-2xl"
          >
            {[
              { icon: FileText, label: "Markdown (.md)", action: exportMarkdown },
              { icon: FileJson, label: "JSON (.json)", action: exportJSON },
              { icon: Code2, label: "Plain Text (.txt)", action: exportText },
            ].map(({ icon: Icon, label, action }) => (
              <button
                key={label}
                onClick={action}
                className="w-full flex items-center gap-3 px-4 py-3 text-sm text-slate-300 hover:text-white hover:bg-white/08 transition-colors text-left"
              >
                <Icon className="w-4 h-4 text-purple-400" />
                {label}
              </button>
            ))}
          </motion.div>
        )}
      </AnimatePresence>

      {open && (
        <div className="fixed inset-0 z-10" onClick={() => setOpen(false)} />
      )}
    </div>
  );
}
