"use client";

import { useState } from "react";
import { motion, AnimatePresence } from "framer-motion";
import type { ResearchSource } from "@/lib/types";
import { ExternalLink, ChevronDown, ChevronUp, Database } from "lucide-react";

interface SourceCardsProps {
  sources: ResearchSource[];
}

export function SourceCards({ sources }: SourceCardsProps) {
  const [expanded, setExpanded] = useState<number | null>(null);
  const [showAll, setShowAll] = useState(false);

  const displayed = showAll ? sources : sources.slice(0, 6);

  const getAuthorityBadge = (score: number) => {
    if (score >= 0.8) return { label: "High Authority", cls: "badge-high" };
    if (score >= 0.6) return { label: "Medium Authority", cls: "badge-medium" };
    return { label: "Low Authority", cls: "badge-low" };
  };

  return (
    <div className="glass rounded-2xl p-7">
      <div className="flex items-center justify-between mb-6">
        <div className="flex items-center gap-2">
          <Database className="w-5 h-5 text-purple-400" />
          <h2 className="text-sm font-semibold text-slate-400 uppercase tracking-wider">
            Sources ({sources.length})
          </h2>
        </div>
      </div>

      <div className="grid md:grid-cols-2 gap-4">
        {displayed.map((source, i) => {
          const badge = getAuthorityBadge(source.authorityScore);
          const isExpanded = expanded === i;

          return (
            <motion.div
              key={source.url}
              initial={{ opacity: 0, y: 12 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ delay: i * 0.06 }}
              className="rounded-xl p-4 transition-all duration-200 cursor-pointer"
              style={{
                background: "rgba(255,255,255,0.04)",
                border: isExpanded
                  ? "1px solid rgba(108,99,255,0.3)"
                  : "1px solid rgba(255,255,255,0.06)",
              }}
              onClick={() => setExpanded(isExpanded ? null : i)}
            >
              {/* Header row */}
              <div className="flex items-start justify-between gap-3 mb-2">
                <div className="flex-1 min-w-0">
                  <p className="text-sm font-semibold text-white leading-snug line-clamp-2 mb-1">
                    {source.title || source.domain}
                  </p>
                  <p className="text-xs text-slate-500">{source.domain}</p>
                </div>
                <div className="flex items-center gap-2 flex-shrink-0">
                  <a
                    href={source.url}
                    target="_blank"
                    rel="noopener noreferrer"
                    onClick={(e) => e.stopPropagation()}
                    className="p-1.5 rounded-lg hover:bg-white/10 text-slate-500 hover:text-white transition-colors"
                  >
                    <ExternalLink className="w-3.5 h-3.5" />
                  </a>
                  {isExpanded ? (
                    <ChevronUp className="w-4 h-4 text-slate-500" />
                  ) : (
                    <ChevronDown className="w-4 h-4 text-slate-500" />
                  )}
                </div>
              </div>

              {/* Scores row */}
              <div className="flex items-center gap-2 flex-wrap mb-3">
                <span className={`badge ${badge.cls}`}>{badge.label}</span>
                <span className="text-xs text-slate-500">
                  Relevance: {Math.round(source.relevanceScore * 100)}%
                </span>
              </div>

              {/* Expanded claims */}
              <AnimatePresence>
                {isExpanded && source.extractedClaims.length > 0 && (
                  <motion.div
                    initial={{ height: 0, opacity: 0 }}
                    animate={{ height: "auto", opacity: 1 }}
                    exit={{ height: 0, opacity: 0 }}
                    transition={{ duration: 0.25 }}
                    className="overflow-hidden"
                  >
                    <div className="border-t border-white/5 pt-3 mt-1">
                      <p className="text-xs font-semibold text-slate-500 mb-2">Extracted Claims</p>
                      <ul className="space-y-2">
                        {source.extractedClaims.map((claim, j) => (
                          <li key={j} className="flex items-start gap-2">
                            <span className="text-xs font-bold text-purple-400 mt-0.5 flex-shrink-0">
                              {claim.value}
                            </span>
                            <span className="text-xs text-slate-400">{claim.context}</span>
                          </li>
                        ))}
                      </ul>
                    </div>
                  </motion.div>
                )}
              </AnimatePresence>
            </motion.div>
          );
        })}
      </div>

      {sources.length > 6 && (
        <button
          onClick={() => setShowAll(!showAll)}
          className="mt-5 w-full py-3 rounded-xl text-sm text-slate-400 hover:text-white transition-colors border border-white/06 hover:border-purple-500/30 hover:bg-white/5"
        >
          {showAll ? "Show Less" : `Show ${sources.length - 6} More Sources`}
        </button>
      )}
    </div>
  );
}
