"use client";

import { useState } from "react";
import { motion, AnimatePresence } from "framer-motion";
import type { ExtractedImage } from "@/lib/types";
import { ImageIcon, X, ExternalLink } from "lucide-react";

interface ImageGalleryProps {
  images: ExtractedImage[];
}

export function ImageGallery({ images }: ImageGalleryProps) {
  const [selected, setSelected] = useState<ExtractedImage | null>(null);
  const [failedUrls, setFailedUrls] = useState<Set<string>>(new Set());

  const validImages = images.filter((img) => !failedUrls.has(img.url));

  if (validImages.length === 0) return null;

  return (
    <div className="glass rounded-2xl p-7">
      <div className="flex items-center gap-2 mb-6">
        <ImageIcon className="w-5 h-5 text-cyan-400" />
        <h2 className="text-sm font-semibold text-slate-400 uppercase tracking-wider">
          Visual Intelligence ({validImages.length} images)
        </h2>
      </div>

      <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-4">
        {validImages.map((img, i) => (
          <motion.div
            key={img.url}
            initial={{ opacity: 0, scale: 0.95 }}
            animate={{ opacity: 1, scale: 1 }}
            transition={{ delay: i * 0.06 }}
            className="group relative cursor-pointer rounded-xl overflow-hidden"
            style={{ aspectRatio: "16/10" }}
            onClick={() => setSelected(img)}
          >
            <img
              src={img.url}
              alt={img.title || "Research image"}
              className="w-full h-full object-cover transition-transform duration-400 group-hover:scale-105"
              onError={() => setFailedUrls((prev) => new Set([...prev, img.url]))}
            />
            <div className="absolute inset-0 bg-gradient-to-t from-black/60 to-transparent opacity-0 group-hover:opacity-100 transition-opacity duration-300 flex items-end p-3">
              <p className="text-xs text-white line-clamp-2">{img.title}</p>
            </div>
          </motion.div>
        ))}
      </div>

      {/* Lightbox */}
      <AnimatePresence>
        {selected && (
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="fixed inset-0 bg-black/80 backdrop-blur-md z-50 flex items-center justify-center p-6"
            onClick={() => setSelected(null)}
          >
            <motion.div
              initial={{ scale: 0.9, opacity: 0 }}
              animate={{ scale: 1, opacity: 1 }}
              exit={{ scale: 0.9, opacity: 0 }}
              className="glass-strong rounded-2xl p-2 max-w-4xl w-full"
              onClick={(e) => e.stopPropagation()}
            >
              <img
                src={selected.url}
                alt={selected.title || ""}
                className="w-full rounded-xl object-contain max-h-[70vh]"
              />
              <div className="flex items-center justify-between p-4">
                <p className="text-sm text-slate-400">{selected.title}</p>
                <div className="flex gap-2">
                  <a
                    href={selected.sourceUrl}
                    target="_blank"
                    rel="noopener noreferrer"
                    className="p-2 rounded-lg glass hover:text-white text-slate-400 transition-colors"
                  >
                    <ExternalLink className="w-4 h-4" />
                  </a>
                  <button
                    onClick={() => setSelected(null)}
                    className="p-2 rounded-lg glass hover:text-white text-slate-400 transition-colors"
                  >
                    <X className="w-4 h-4" />
                  </button>
                </div>
              </div>
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
}
