"use client";

import { useState, useRef, useCallback } from "react";
import { motion, AnimatePresence } from "framer-motion";
import type { ResearchReport } from "@/lib/types";
import { Navbar } from "@/components/Navbar";
import { HeroSection } from "@/components/HeroSection";
import { ProgressPanel } from "@/components/ProgressPanel";
import { ReportPanel } from "@/components/ReportPanel";

interface ProgressEvent {
  step: string;
  message: string;
  progress: number;
  details?: string[];
}

export default function HomePage() {
  const [query, setQuery] = useState("");
  const [isResearching, setIsResearching] = useState(false);
  const [report, setReport] = useState<ResearchReport | null>(null);
  const [progressEvents, setProgressEvents] = useState<ProgressEvent[]>([]);
  const [currentProgress, setCurrentProgress] = useState(0);
  const [currentStep, setCurrentStep] = useState("");
  const [error, setError] = useState<string | null>(null);
  const abortRef = useRef<AbortController | null>(null);

  const handleResearch = useCallback(async (q: string) => {
    if (!q.trim() || isResearching) return;
    
    setIsResearching(true);
    setReport(null);
    setProgressEvents([]);
    setCurrentProgress(0);
    setCurrentStep("intents");
    setError(null);

    abortRef.current = new AbortController();

    try {
      const res = await fetch("/api/research", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ query: q.trim() }),
        signal: abortRef.current.signal,
      });

      if (!res.ok) throw new Error("Research request failed");

      const reader = res.body!.getReader();
      const decoder = new TextDecoder();
      let buffer = "";

      while (true) {
        const { done, value } = await reader.read();
        if (done) break;

        buffer += decoder.decode(value, { stream: true });
        const lines = buffer.split("\n");
        buffer = lines.pop() ?? "";

        for (const line of lines) {
          if (!line.startsWith("data: ")) continue;
          try {
            const data = JSON.parse(line.slice(6));
            if (data.type === "progress") {
              setCurrentProgress(data.progress);
              setCurrentStep(data.step);
              setProgressEvents((prev) => [...prev, data]);
            } else if (data.type === "complete") {
              setReport(data.report);
              setCurrentProgress(100);
            } else if (data.type === "error") {
              setError(data.message);
            }
          } catch {
            // skip malformed lines
          }
        }
      }
    } catch (err: unknown) {
      if (err instanceof Error && err.name !== "AbortError") {
        setError(err.message || "Research failed. Please try again.");
      }
    } finally {
      setIsResearching(false);
    }
  }, [isResearching]);

  const handleNewResearch = () => {
    abortRef.current?.abort();
    setReport(null);
    setProgressEvents([]);
    setCurrentProgress(0);
    setIsResearching(false);
    setError(null);
  };

  return (
    <div className="min-h-screen relative">
      {/* Backgrounds */}
      <div className="aurora-bg">
        <div className="aurora-orb-1" />
        <div className="aurora-orb-2" />
        <div className="aurora-orb-3" />
      </div>
      <div className="grid-overlay" />
      <div className="noise-overlay" />

      {/* Content */}
      <div className="relative z-10">
        <Navbar onNewResearch={handleNewResearch} hasReport={!!report || isResearching} />

        <AnimatePresence mode="wait">
          {!isResearching && !report && !error && (
            <motion.div
              key="hero"
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              exit={{ opacity: 0, y: -20 }}
              transition={{ duration: 0.4 }}
            >
              <HeroSection
                query={query}
                setQuery={setQuery}
                onResearch={handleResearch}
              />
            </motion.div>
          )}

          {(isResearching || error) && !report && (
            <motion.div
              key="progress"
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0 }}
              transition={{ duration: 0.4 }}
            >
              <ProgressPanel
                query={query}
                progressEvents={progressEvents}
                currentProgress={currentProgress}
                currentStep={currentStep}
                error={error}
                onNewResearch={handleNewResearch}
              />
            </motion.div>
          )}

          {report && (
            <motion.div
              key="report"
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.5 }}
            >
              <ReportPanel report={report} onNewResearch={handleNewResearch} />
            </motion.div>
          )}
        </AnimatePresence>
      </div>
    </div>
  );
}
