"use client";

import { useEffect, useState } from "react";
import { motion } from "framer-motion";

interface ConfidenceMeterProps {
  score: number; // 0-100
}

export function ConfidenceMeter({ score }: ConfidenceMeterProps) {
  const [animated, setAnimated] = useState(0);

  useEffect(() => {
    const timer = setTimeout(() => setAnimated(score), 200);
    return () => clearTimeout(timer);
  }, [score]);

  const radius = 80;
  const circumference = 2 * Math.PI * radius;
  const strokeDashoffset = circumference - (animated / 100) * circumference;

  const color =
    score >= 80 ? "#00ffb2" : score >= 60 ? "#00d4ff" : score >= 40 ? "#fbbf24" : "#ff6b9d";

  const label =
    score >= 80 ? "High Confidence"
    : score >= 60 ? "Moderate Confidence"
    : score >= 40 ? "Low Confidence"
    : "Uncertain";

  return (
    <div className="flex flex-col items-center gap-3">
      <div className="relative w-[200px] h-[200px]">
        <svg width="200" height="200" viewBox="0 0 200 200" className="-rotate-90">
          {/* Background ring */}
          <circle
            cx="100" cy="100" r={radius}
            fill="none"
            stroke="rgba(255,255,255,0.06)"
            strokeWidth="10"
          />
          {/* Progress ring */}
          <motion.circle
            cx="100" cy="100" r={radius}
            fill="none"
            stroke={color}
            strokeWidth="10"
            strokeLinecap="round"
            strokeDasharray={circumference}
            initial={{ strokeDashoffset: circumference }}
            animate={{ strokeDashoffset }}
            transition={{ duration: 1.5, ease: "easeOut", delay: 0.3 }}
            style={{
              filter: `drop-shadow(0 0 8px ${color}80)`,
            }}
          />
        </svg>

        {/* Center text */}
        <div className="absolute inset-0 flex flex-col items-center justify-center">
          <motion.span
            initial={{ opacity: 0, scale: 0.5 }}
            animate={{ opacity: 1, scale: 1 }}
            transition={{ delay: 0.5, duration: 0.4 }}
            className="text-5xl font-black"
            style={{ color }}
          >
            {score}%
          </motion.span>
          <span className="text-xs text-slate-500 mt-1">Confidence</span>
        </div>
      </div>

      <div
        className="badge text-xs font-semibold"
        style={{
          background: `${color}18`,
          color,
          border: `1px solid ${color}30`,
          padding: "4px 14px",
          borderRadius: "99px",
        }}
      >
        {label}
      </div>
    </div>
  );
}
