"use client";

import { motion } from "framer-motion";
import { Search, Globe, BarChart2, Brain, CheckCircle, AlertCircle, RefreshCw } from "lucide-react";

interface ProgressEvent {
  step: string;
  message: string;
  progress: number;
  details?: string[];
}

interface ProgressPanelProps {
  query: string;
  progressEvents: ProgressEvent[];
  currentProgress: number;
  currentStep: string;
  error: string | null;
  onNewResearch: () => void;
}

const STEPS = [
  { id: "intents", icon: Search, label: "Generating Intents", color: "#6c63ff" },
  { id: "searching", icon: Globe, label: "Discovering Sources", color: "#00d4ff" },
  { id: "extracting", icon: BarChart2, label: "Extracting Data", color: "#00ffb2" },
  { id: "validating", icon: Brain, label: "Cross-Validating", color: "#ff6b9d" },
  { id: "generating", icon: CheckCircle, label: "Generating Report", color: "#6c63ff" },
];

const stepOrder = ["intents", "searching", "extracting", "validating", "generating"];

export function ProgressPanel({ query, progressEvents, currentProgress, currentStep, error, onNewResearch }: ProgressPanelProps) {
  const currentStepIdx = stepOrder.indexOf(currentStep);
  const lastEvents = progressEvents.slice(-8);

  return (
    <div className="min-h-[85vh] flex flex-col items-center justify-center px-6 py-12">
      <div className="w-full max-w-2xl">
        {/* Query display */}
        <motion.div
          initial={{ opacity: 0, y: -10 }}
          animate={{ opacity: 1, y: 0 }}
          className="glass rounded-2xl p-5 mb-6 flex items-start gap-3"
        >
          <Search className="w-5 h-5 text-purple-400 mt-0.5 flex-shrink-0" />
          <div>
            <p className="text-xs text-slate-500 mb-1">Researching</p>
            <p className="text-white font-medium">{query}</p>
          </div>
        </motion.div>

        {error ? (
          <motion.div
            initial={{ opacity: 0, scale: 0.95 }}
            animate={{ opacity: 1, scale: 1 }}
            className="glass rounded-2xl p-8 text-center"
          >
            <AlertCircle className="w-12 h-12 text-red-400 mx-auto mb-4" />
            <h3 className="text-lg font-semibold mb-2 text-red-300">Research Failed</h3>
            <p className="text-slate-400 text-sm mb-6">{error}</p>
            <button
              onClick={onNewResearch}
              className="btn-gradient px-6 py-2.5 rounded-xl font-semibold text-sm flex items-center gap-2 mx-auto"
            >
              <RefreshCw className="w-4 h-4" />
              Try Again
            </button>
          </motion.div>
        ) : (
          <>
            {/* Overall progress bar */}
            <motion.div
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              className="glass rounded-2xl p-6 mb-4"
            >
              <div className="flex items-center justify-between mb-3">
                <span className="text-sm font-semibold text-slate-300">Research Progress</span>
                <span className="text-sm font-bold gradient-text">{Math.round(currentProgress)}%</span>
              </div>
              <div className="progress-bar">
                <motion.div
                  className="progress-fill"
                  initial={{ width: 0 }}
                  animate={{ width: `${currentProgress}%` }}
                  transition={{ duration: 0.6, ease: "easeOut" }}
                />
              </div>
            </motion.div>

            {/* Step timeline */}
            <div className="glass rounded-2xl p-6 mb-4">
              <h3 className="text-sm font-semibold text-slate-400 mb-5">Research Pipeline</h3>
              <div className="space-y-4">
                {STEPS.map((step, idx) => {
                  const Icon = step.icon;
                  const isDone = currentStepIdx > idx;
                  const isActive = currentStepIdx === idx;
                  const isPending = currentStepIdx < idx;

                  return (
                    <motion.div
                      key={step.id}
                      initial={{ opacity: 0, x: -10 }}
                      animate={{ opacity: 1, x: 0 }}
                      transition={{ delay: idx * 0.08 }}
                      className="flex items-center gap-4"
                    >
                      {/* Icon */}
                      <div
                        className="w-9 h-9 rounded-xl flex items-center justify-center flex-shrink-0 transition-all duration-500"
                        style={{
                          background: isDone
                            ? `${step.color}22`
                            : isActive
                            ? `${step.color}33`
                            : "rgba(255,255,255,0.04)",
                          border: `1px solid ${isDone || isActive ? step.color + "44" : "rgba(255,255,255,0.06)"}`,
                        }}
                      >
                        <Icon
                          className="w-4 h-4 transition-all duration-500"
                          style={{
                            color: isDone ? "#00ffb2" : isActive ? step.color : "#475569",
                          }}
                        />
                      </div>

                      {/* Label & status */}
                      <div className="flex-1 min-w-0">
                        <div className="flex items-center gap-2">
                          <span
                            className="text-sm font-medium transition-colors duration-300"
                            style={{
                              color: isDone ? "#00ffb2" : isActive ? "#fff" : "#475569",
                            }}
                          >
                            {step.label}
                          </span>
                          {isActive && (
                            <motion.div
                              animate={{ opacity: [1, 0.3, 1] }}
                              transition={{ duration: 1.2, repeat: Infinity }}
                              className="w-1.5 h-1.5 rounded-full bg-current"
                              style={{ color: step.color }}
                            />
                          )}
                          {isDone && <CheckCircle className="w-3.5 h-3.5 text-green-400" />}
                        </div>
                      </div>

                      {/* Step indicator */}
                      <span className="text-xs text-slate-600">{idx + 1}/5</span>
                    </motion.div>
                  );
                })}
              </div>
            </div>

            {/* Live log */}
            {lastEvents.length > 0 && (
              <motion.div
                initial={{ opacity: 0 }}
                animate={{ opacity: 1 }}
                className="glass rounded-2xl p-4"
              >
                <h3 className="text-xs font-semibold text-slate-500 mb-3 uppercase tracking-wider">Live Log</h3>
                <div className="space-y-2 max-h-48 overflow-y-auto">
                  {lastEvents.map((evt, i) => (
                    <motion.div
                      key={i}
                      initial={{ opacity: 0, x: -6 }}
                      animate={{ opacity: 1, x: 0 }}
                      className="flex items-start gap-2"
                    >
                      <div className="w-1.5 h-1.5 rounded-full bg-purple-400 mt-1.5 flex-shrink-0" />
                      <span className="text-xs text-slate-400 leading-relaxed">{evt.message}</span>
                    </motion.div>
                  ))}
                </div>
              </motion.div>
            )}
          </>
        )}
      </div>
    </div>
  );
}
