"use client";

import { useState, KeyboardEvent } from "react";
import { motion } from "framer-motion";
import { Search, Sparkles, ArrowRight, Globe, Shield, Zap } from "lucide-react";

const EXAMPLE_QUERIES = [
  "How many AirPods were sold this year?",
  "Nvidia revenue from AI chips in 2025",
  "EV sales in India in 2025",
  "ChatGPT vs Gemini market share",
  "Apple Vision Pro units sold",
];

const STATS = [
  { value: "100M+", label: "Pages Analyzed" },
  { value: "98%", label: "Fact Accuracy" },
  { value: "15s", label: "Avg Research Time" },
  { value: "12+", label: "Sources Per Query" },
];

interface HeroSectionProps {
  query: string;
  setQuery: (q: string) => void;
  onResearch: (q: string) => void;
}

export function HeroSection({ query, setQuery, onResearch }: HeroSectionProps) {
  const [focused, setFocused] = useState(false);

  const handleKeyDown = (e: KeyboardEvent<HTMLTextAreaElement>) => {
    if (e.key === "Enter" && !e.shiftKey) {
      e.preventDefault();
      if (query.trim()) onResearch(query);
    }
  };

  return (
    <section className="min-h-[85vh] flex flex-col items-center justify-center px-6 text-center pt-4 pb-20">
      {/* Badge */}
      <motion.div
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ delay: 0.1 }}
        className="inline-flex items-center gap-2 px-4 py-2 rounded-full glass text-sm text-slate-300 mb-8"
      >
        <Sparkles className="w-4 h-4 text-purple-400" />
        <span>Powered by Context.dev Web Intelligence + GPT-4o</span>
      </motion.div>

      {/* Headline */}
      <motion.h1
        initial={{ opacity: 0, y: 30 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ delay: 0.2, duration: 0.7 }}
        className="text-5xl md:text-7xl font-black leading-[1.05] max-w-5xl mb-6"
      >
        Research Anything.{" "}
        <span className="gradient-text">Verify Everything.</span>
      </motion.h1>

      <motion.p
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ delay: 0.35 }}
        className="text-lg md:text-xl text-slate-400 max-w-2xl mb-12 leading-relaxed"
      >
        AI-powered research engine that crawls the web, validates facts,
        cross-references sources, and delivers trustworthy answers with
        confidence scoring.
      </motion.p>

      {/* Search Box */}
      <motion.div
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ delay: 0.45 }}
        className="w-full max-w-3xl"
      >
        <div
          className={`relative rounded-2xl transition-all duration-300 ${
            focused
              ? "shadow-[0_0_0_2px_rgba(108,99,255,0.5),0_20px_60px_rgba(108,99,255,0.15)]"
              : "shadow-[0_8px_32px_rgba(0,0,0,0.3)]"
          }`}
        >
          <div className="glass-strong p-3 rounded-2xl">
            <div className="flex items-start gap-3">
              <Search className="w-5 h-5 text-slate-500 mt-3.5 ml-2 flex-shrink-0" />
              <textarea
                value={query}
                onChange={(e) => setQuery(e.target.value)}
                onKeyDown={handleKeyDown}
                onFocus={() => setFocused(true)}
                onBlur={() => setFocused(false)}
                placeholder="Ask anything... e.g. How many AirPods were sold this year?"
                rows={2}
                className="flex-1 bg-transparent text-white placeholder-slate-500 resize-none text-base leading-relaxed outline-none py-3"
              />
              <button
                onClick={() => query.trim() && onResearch(query)}
                disabled={!query.trim()}
                className="btn-gradient rounded-xl px-5 py-3 mt-1 flex items-center gap-2 font-semibold text-sm disabled:opacity-40 disabled:cursor-not-allowed transition-all flex-shrink-0"
              >
                <span>Research</span>
                <ArrowRight className="w-4 h-4" />
              </button>
            </div>
          </div>
        </div>

        {/* Example queries */}
        <div className="flex flex-wrap justify-center gap-2 mt-4">
          {EXAMPLE_QUERIES.map((q) => (
            <button
              key={q}
              onClick={() => { setQuery(q); onResearch(q); }}
              className="px-3 py-1.5 rounded-full text-xs text-slate-400 glass hover:text-white hover:border-purple-500/40 transition-all duration-200"
            >
              {q}
            </button>
          ))}
        </div>
      </motion.div>

      {/* Stats */}
      <motion.div
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ delay: 0.6 }}
        className="grid grid-cols-2 md:grid-cols-4 gap-4 mt-16 w-full max-w-3xl"
      >
        {STATS.map((s, i) => (
          <motion.div
            key={s.label}
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.65 + i * 0.08 }}
            className="glass rounded-2xl p-5 text-center"
          >
            <div className="text-3xl font-black gradient-text mb-1">{s.value}</div>
            <div className="text-xs text-slate-500">{s.label}</div>
          </motion.div>
        ))}
      </motion.div>

      {/* Features row */}
      <motion.div
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        transition={{ delay: 0.9 }}
        className="flex flex-wrap justify-center gap-6 mt-12 text-sm text-slate-500"
      >
        {[
          { icon: Globe, text: "Multi-source crawling" },
          { icon: Shield, text: "Cross-validated facts" },
          { icon: Zap, text: "Real-time progress" },
        ].map(({ icon: Icon, text }) => (
          <div key={text} className="flex items-center gap-2">
            <Icon className="w-4 h-4 text-purple-400" />
            <span>{text}</span>
          </div>
        ))}
      </motion.div>
    </section>
  );
}
